import {IonIcon} from '@ionic/react';
import Link, {ThLink} from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
const _aromaphile = {title: "Aromaphile", jsx: <><h2 id="arc-mesmerist-aromaphile-aromaphile">Aromaphile</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 18</Link><br/>Rather than employ the baleful glares of the typical mesmerist, aromaphiles hypnotize others using an array of sickeningly sweet scents developed from their unique ghoran physiology.</p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="arc-mesmerist-aromaphile--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><Link to="/race/ghoran">Ghoran</Link></td></tr></tbody></table></ScrollContainer></div><div className="ability p"><div className="abIcon"><Link to="/icons/abstract-091"><IonIcon icon="/icons/abstract-091.svg" color="secondary" /></Link><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-aromaphile-hypnotic-aroma-su" data-hash-target><div className="box">Hypnotic Aroma (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Hypnotic stare, painful stare, towering ego</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Swift Action</div></div><div className="abEnd"><div className="box">An aromaphile can use unique aspects of ghoran biology to release intoxicating aromas in a 10-foot-radius <Link to="/misc/burst">burst</Link> centered on him. All creatures within this area, as well as creatures with <Link to="/umr/scent">scent</Link> within 30 feet, take a -2 penalty on Will saving throws. The aroma hovers around the aromaphile, moving with him, and lasts for 1 minute.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 8th Level</div></div><div className="abEnd"><div className="box">This penalty becomes -3.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">The hypnotic aroma must be inhaled to be effective, and creatures that choose to <Link to="/misc/hold_their_breath">hold their breath</Link>, do not breathe, or are immune to inhaled poisons are immune to its effect.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-aromaphile-debilitating-aroma-su" data-hash-target><div className="box">Debilitating Aroma (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Bold stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An aromaphile can imbue his hypnotic aroma with another effect, chosen from those listed within the <em>bold stare</em> mesmerist class feature. However, they affect creatures affected by his <em>hypnotic aroma</em> for as long as they are affected by that ability.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 3rd Level</div></div><div className="abEnd"><div className="box">The aromaphile selects a new <em>debilitating aroma.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 7th Level</div></div><div className="abEnd"><div className="box">The aromaphile selects a new <em>debilitating aroma.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">The aromaphile selects a new <em>debilitating aroma.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 15th Level</div></div><div className="abEnd"><div className="box">The aromaphile selects a new <em>debilitating aroma.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 19th Level</div></div><div className="abEnd"><div className="box">The aromaphile selects a new <em>debilitating aroma.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">The aromaphile chooses one option each time he gains a new debilitating aroma improvement, and the choice can't be changed later. The aromaphile can't choose the same debilitating aroma more than once unless otherwise noted.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-palm"><IonIcon icon="/icons/magic-palm.svg" color="secondary" /></Link><Link to="/icons/heart-plus"><IonIcon icon="/icons/heart-plus.svg" color="secondary" /></Link><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-aromaphile-aromatic-manipulation-su" data-hash-target><div className="box">Aromatic Manipulation (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Mental potency</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Touch treatment</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box"><p>The aromaphile can touch a creature affected by his <em>hypnotic aroma</em> to alter its mental state. This functions as the <em>touch treatment</em> class feature, except the aromaphile cannot remove the <em>confused, cowering,</em> or <em>stunned</em> conditions, and he cannot <em>break enchantments</em> using this ability. Instead, he adds <Link to="/misc/fatigued">fatigued</Link> to his list of minor conditions and <Link to="/misc/exhausted">exhausted</Link> to his list of greater conditions.</p>
<p>An aromaphile can also use this ability to inflict hampering conditions on a target by touching it. Initially, he can cause his target to become <Link to="/misc/fascinated">fascinated</Link> by his <em>aroma,</em> but he gains more abilities as he gains levels.</p>
</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">His touch can deaden the target's emotions (as per <Link to="/spell/calm_emotions">calm emotions</Link>).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">His touch can cause the target to become <Link to="/misc/stunned">stunned</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 14th Level</div></div><div className="abEnd"><div className="box">His touch can cause the target to fall asleep (as per <Link to="/spell/deep_slumber">deep slumber</Link>, except the Hit Die limit is equal to the aromaphile's level + 2).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">The target can attempt a Will save to negate these ill effects (DC = 10 + half the aromaphile's level + the aromaphile's Charisma modifier). On a failed save, the target gains the chosen condition for a number of rounds equal to the aromaphile's level. Each round that the target is affected, it can attempt a new Will save at the same DC to end the effect early. If the target succeeds at such a save, its turn immediately ends.</div></div></div></div>
</>};
const _autohypnotist = {title: "Autohypnotist", jsx: <><h2 id="arc-mesmerist-autohypnotist-autohypnotist">Autohypnotist</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 17</Link><br/>An autohypnotist has incredibly powerful psychic abilities that he can't entirely control. As a result, maintaining his powers against an opponent hinders him as much as his target.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-autohypnotist-autohypnosis-su" data-hash-target><div className="box">Autohypnosis (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Hypnotic stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box"><p>An autohypnotist has mastered techniques that make his <em>hypnotic stare</em> ability more potent, but at a terrible cost - the autohypnotist succumbs to his own power when he uses it. Whenever the autohypnotist focuses his stare on an opponent, the penalties that opponent takes from the <em>hypnotic stare</em> (as well as any <em>bold stare</em> improvements or stare feats that the autohypnotist has) increase by 1. However, the autohypnotist takes the same penalties as his target while focusing his stare, including those of any <em>bold stare</em> improvements he has.</p>
<p>An autohypnotist can reduce or negate the penalty he imposes upon himself with his <em>hypnotic stare,</em> but doing so allows his opponent an opportunity to escape from the stare as well. The autohypnotist can reduce the penalty he takes from his <em>hypnotic stare</em> ability by <Link to="/misc/half">half</Link> for 1 round as a <strong className="hl">swift action</strong>. If he does so, there is a 25% chance that his <em>hypnotic stare</em> ends altogether. Alternatively, he can choose to negate the penalty he takes from his <em>hypnotic stare</em> for 1 round, but his <em>hypnotic stare</em> then has a 50% chance of ending.</p>
</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/abstract-091"><IonIcon icon="/icons/abstract-091.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-autohypnotist-wide-stare-su" data-hash-target><div className="box">Wide Stare (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Mental potency</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">Whenever an autohypnotist is focusing his stare on a foe, he can broaden his <em>hypnotic stare.</em> When he does so, all creatures within 10 feet of his opponent take penalties from the mesmerist's <em>hypnotic stare</em> and <em>bold stare</em> class features as if he were maintaining his <em>hypnotic stare</em> against each of those creatures, except such creatures treat his <em>hypnotic stare</em> penalty as if it were 2 lower.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">When the autohypnotist uses this ability, he cannot exclude allies or any other creatures from this effect. If the autohypnotist's <em>hypnotic stare</em> ends for the focused opponent, this effect ends.</div></div></div></div>
</>};
const _chart_caster = {title: "Chart Caster", jsx: <><h2 id="arc-mesmerist-chart_caster-chart-caster">Chart Caster</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 10</Link><br/>Lirgeni astrologists would divine their futures by consulting star charts, but some had no talent for astrology and simply faked their results. When prophecy died with Aroden, a few Lirgeni survivors continued with this "reliable" method.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/skills"><IonIcon icon="/icons/skills.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-chart_caster-undefined" data-hash-target><div className="box">Class Skills</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Class skills</div></div></div><div className="abPair"><div className="abStart"><div className="box">New Class Skills</div></div><div className="abEnd"><div className="box"><Link to="/skill/knowledge_nature">Knowledge (nature)</Link> (INT), <Link to="/skill/knowledge_planes">Knowledge (planes)</Link> (INT)</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-chart_caster-subject-of-the-stars-su" data-hash-target><div className="box">Subject of the Stars (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Mesmerist tricks, manifold tricks</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box"><p>A chart caster cannot implant tricks as a standard action. Instead, he can spend 5 minutes to implant multiple tricks in a single willing target. The number of tricks he can implant per day is unchanged from the regular mesmerist class, but he can apply as many of those tricks as he chooses on a single use of this ability.</p>
<p>If implanting tricks in himself, the caster merely spends 5 minutes in contemplation; otherwise, he consults star charts while ritually asking the creature questions, and still must touch them to do so. He can select multiple instances of the same trick to implant in a single subject.</p>
</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 5th Level</div></div><div className="abEnd"><div className="box">A chart caster can implant 2 different subjects with multiple instances of one trick each and can choose a different trick for each subject.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">A chart caster can implant 3 different subjects with multiple instances of one trick each and can choose a different trick for each subject.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 13th Level</div></div><div className="abEnd"><div className="box">A chart caster can implant 4 different subjects with multiple instances of one trick each and can choose a different trick for each subject.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 17th Level</div></div><div className="abEnd"><div className="box">A chart caster can implant 5 different subjects with multiple instances of one trick each and can choose a different trick for each subject.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">Using this ability again on an existing subject or to implant any trick on a new subject ends all previously implanted tricks. The caster can trigger only one instance of the same trick on a given subject per round.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/shield-reflect"><IonIcon icon="/icons/shield-reflect.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-chart_caster-feign-destiny-su" data-hash-target><div className="box">Feign Destiny (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch treatment</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">Charisma modifier times/day</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Immediate Action</div></div><div className="abEnd"><div className="box">A chart caster can grant an ally a +1 competence bonus on a failed attack roll, saving throw, or skill check by reminding his ally of their destined success. The chart caster must use his ability within 1 round of the failed check, and his ally must be within 30 feet of him when he does. If the bonus is enough to turn the failure into a success, the ally succeeds at the check.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">The bonus becomes +2.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">The bonus increases to +3.</div></div></div></div>
</>};
const _cult_master = {title: "Cult Master", jsx: <><h2 id="arc-mesmerist-cult_master-cult-master">Cult Master</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 96</Link><br/>The leaders of some cults are simply charlatans, bathing in the adulation of their followers. Others believe themselves to be truly in touch with an unknown power, bringing their unique messages to those willing to follow and obey them.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-cult_master-insidious-personality-ex" data-hash-target><div className="box">Insidious Personality (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Consummate liar</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A cult master adds 1/2 his class level (minimum 1) as a bonus on all Diplomacy checks.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/shield-reflect"><IonIcon icon="/icons/shield-reflect.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-cult_master-fanatical-stare-su" data-hash-target><div className="box">Fanatical Stare (Su)</div><div className="flavor">A cult master can turn his gaze on a creature to fill it with fervent belief in the cult master.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Painful stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The target of the gaze gains a competence bonus on attack rolls and weapon damage rolls. This bonus is equal to 1 + <Link to="/misc/one_sixth">one-sixth</Link> of his mesmerist level.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">Instead of taking the <em>hypnotic stare's</em> penalty on Will saves, the target gains a bonus of an equal amount on Will saves. The bonuses don't apply to attacks against the cult master or on saves against the cult master's spells or abilities. The cult master can also suppress any penalties inflicted by his stare for the target.</div></div></div></div>
<div className="ability p hasSubs"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-cult_master-cult-tricks-su" data-hash-target><div className="box">Cult Tricks (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">The following new tricks can be selected by a cult master. These tricks can be implanted only in a cohort or follower of the cult master.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-cult_master-double" data-hash-target><div className="box">Double</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An illusion makes either the cult master's cohort or one of his followers appear to be him. The cult master can trigger this trick when he is targeted by an attack, provided he is adjacent to the subject, to give the attack a 50% miss chance. If the attack misses the cult master, it targets the subject instead. This is an illusion (glamer) effect.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-cult_master-extol" data-hash-target><div className="box">Extol</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Mesmerist tricks</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A mental compulsion causes a cohort or follower to extol the virtues of the cult master. The cult master can trigger this trick whenever he attempts a Diplomacy check, as long as he is within 60 feet of the subject. The subject takes the <Link to="/rule/aid_another">aid another</Link> action on the cult master's Diplomacy check. If the subject is successful, the cult master gains a +4 bonus on his check. This is an enchantment (compulsion) effect.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/heart-plus"><IonIcon icon="/icons/heart-plus.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-cult_master-false-healing-su" data-hash-target><div className="box">False Healing (Su)</div><div className="flavor">A cult master can provide temporary healing by using his psychic powers to trick the mind.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">3rd- and 6th-level touch treatments</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">3 + Charisma modifier times/day</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">The cult master must be able to touch his target. The cult master grants a number of <Link to="/rule/temporary_hit_points">temporary hit points</Link> equal to 1d8 + his Charisma modifier to the target.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">The cult master can either grant a number of temporary hit points equal to 2d8 + his Charisma modifier to the target or temporarily remove 1d4 points of <Link to="/rule/ability_damage">ability damage</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">This can be used as a <strong className="hl">swift action</strong> if the cult master uses it on himself. A creature can receive the effect of the <em>false healing</em> only once per day. The temporary hit points or reduction in ability damage lasts a number of hours equal to the cult master's class level.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-cult_master-faithful-followers-ex" data-hash-target><div className="box">Faithful Followers (Ex)</div><div className="flavor">A cult master begins to attract followers to his espoused beliefs, thanks to his magnetic personality.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">7th-level bold stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 7th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The cult master gains <Link to="/feat/leadership">Leadership</Link> as a bonus feat.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-cult_master-fanatical-devotion-ex" data-hash-target><div className="box">Fanatical Devotion (Ex)</div><div className="flavor">A cult master has manipulated his cohort and followers into becoming utterly devoted to him.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">10th- and 14th-level touch treatments</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 10th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">The cult master no longer takes a penalty to his Leadership score for being aloof or cruel. Additionally, the DCs of all enchantment spells the cult master casts on his cohort and followers increase by 4.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 14th Level</div></div><div className="abEnd"><div className="box">The cult master no longer takes a penalty to his Leadership score for any cohorts or followers he has killed or caused to be killed.</div></div></div></div>
<div className="ability p hasSubs"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-cult_master-masterful-cult-tricks-su" data-hash-target><div className="box">Masterful Cult Tricks (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box">Prerequisites</div></div><div className="abEnd"><div className="box">12th-level mesmerist</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Masterful tricks</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">The following new master tricks can be selected by any cult master of 12th level or higher. These tricks can be implanted only in a cohort or follower of the cult master.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-cult_master-avenge-me" data-hash-target><div className="box">Avenge Me</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The cult master creates a compulsion for one of his followers to avenge him. Whenever the cult master takes hit point damage from an attack, he can trigger this trick as long as he is within 60 feet of the subject. The subject is immediately affected as if by the <Link to="/spell/rage">rage</Link> spell for 1 round per mesmerist level.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-cult_master-die-for-me" data-hash-target><div className="box">Die for Me</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The cult master instills within either his cohort or one of his followers the desire to give her life for him. The cult master can trigger this trick whenever he would take hit point damage from an attack, spell, or effect and the subject is with 60 feet of him. Half the damage is psychically transferred to the subject. This is an enchantment (compulsion) effect.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-cult_master-reborn-su" data-hash-target><div className="box">Reborn (Su)</div><div className="flavor">A cult master can ensure his own survival upon his death.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Rule minds</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The cult master can perform a 1-hour ceremony costing 5,000 gp in rare materials in which he uses his psychic powers to implant a small portion of his essence into his cohort, who must be a minimum of 17th level. When the cult master dies, in 7 days the cohort physically and mentally transforms into the cult master as if <Link to="/spell/clone">clone</Link> had been cast, except that the cohort's body takes the place of the inert body.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">The cult master can't use this ability again until he gains a new cohort of at least 17th level and performs the necessary ceremony. The cohort can't be brought back to life except through <Link to="/spell/miracle">miracle</Link> or <Link to="/spell/wish">wish</Link>.</div></div></div></div>
</>};
const _dreamstalker = {title: "Dreamstalker", jsx: <><h2 id="arc-mesmerist-dreamstalker-dreamstalker">Dreamstalker</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 60</Link><br/>Many mesmerists concentrate their studies on conscious, rational thought, but dreamstalkers instead delve into the unleashed unconscious mind that wanders free in dreams.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-dreamstalker-dreams-of-pain" data-hash-target><div className="box">Dreams of Pain</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Painful stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">A dreamstalker's <em>painful stare</em> deals nonlethal damage.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/spell-book"><IonIcon icon="/icons/spell-book.svg" color="secondary" /></Link><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-dreamstalker-somnomancer" data-hash-target><div className="box">Somnomancer</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">1st-level mesmerist trick</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Mesmerist tricks</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A dreamstalker gains the <Link to="/hex/slumber">slumber</Link> hex. Furthermore, when she would normally gain a new mesmerist trick, she can learn additional spells instead. Each time she does so, she adds two of the following spells of a level she can currently cast to her list of spells known.</div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">1st</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/oneiric_horror">Oneiric horror</Link>, <Link to="/spell/sleep">sleep</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">2nd</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/detect_mindscape">Detect mindscape</Link>, <Link to="/spell/greater_oneiric_horror">greater oneiric horror</Link>, <Link to="/spell/instigate_psychic_duel">instigate psychic duel</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">3rd</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/deep_slumber">Deep slumber</Link>, <Link to="/spell/minor_dream">minor dream</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">4th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/create_mindscape">Create mindscape</Link>, <Link to="/spell/dream">dream</Link>, <Link to="/spell/forgetful_slumber">forgetful slumber</Link>, <Link to="/spell/mindscape_door">mindscape door</Link>, <Link to="/spell/sleepwalk">sleepwalk</Link>, <Link to="/spell/sleepwalking_suggestion">sleepwalking suggestion</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">5th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/cloak_of_dreams">Cloak of dreams</Link>, <Link to="/spell/dream_council">dream council</Link>, <Link to="/spell/dream_scan">dream scan</Link>, <Link to="/spell/symbol_of_sleep">symbol of sleep</Link>, <Link to="/spell/waves_of_fatigue">waves of fatigue</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">6th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/dream_travel">Dream travel</Link>, <Link to="/spell/greater_create_mindscape">greater create mindscape</Link>, <Link to="/spell/waves_of_exhaustion">waves of exhaustion</Link></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">She can take the <Link to="/hex/nightmares">nightmares</Link> or <Link to="/hex/vision">vision</Link> hex instead of gaining a new mesmerist trick.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 18th Level</div></div><div className="abEnd"><div className="box">She can select the <Link to="/hex/eternal_slumber">eternal slumber</Link> hex in place of a mesmerist trick.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">The dreamstalker's effective witch level is equal to her mesmerist level, and she can activate a hex only by expending two daily uses of mesmerist tricks. The save DCs for her hexes are Charisma-based.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-dreamstalker-sleepless-ex" data-hash-target><div className="box">Sleepless (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Towering ego</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A dreamstalker gains immunity to sleep effects and a bonus equal to her Charisma bonus on saving throws against <Link to="/misc/fatigue">fatigue</Link> and <Link to="/misc/exhaustion">exhaustion</Link>. She loses both benefits when under an effect that would prevent her from providing an <Link to="/rule/emotion_component">emotion component</Link>.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-dreamstalker-touch-of-night-su" data-hash-target><div className="box">Touch of Night (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Touch treatment</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A dreamstalker can't remove shaken, frightened, sickened, cowering, nauseated, or panicked conditions using her <em>touch treatment.</em> However, she can remove fatigue or magical sleep (other than hard-to-remove magical sleep such as the <em>eternal slumber</em> hex) as a minor condition, <Link to="/misc/staggered">staggered</Link> as a moderate condition, and exhausted as a greater condition. As normal, removing fatigue or exhaustion only removes the condition, not the underlying cause, such as lack of sleep.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-dreamstalker-dreamwalker-su" data-hash-target><div className="box">Dreamwalker (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Manifold tricks</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A dreamstalker treats <Link to="/rule/dreamscape">dreamscapes</Link> as a <Link to="/ability/favored_terrain">favored terrain</Link>, as per the <Link to="/class/ranger">ranger</Link> ability, gaining a +2 bonus that increases by 2 every 4 mesmerist levels after 5th. While in a dreamscape, she also treats any creature from the <Link to="/rule/dimension_of_dreams_oa">Dimension of Dreams</Link> (including dreamed figments) as her <Link to="/ability/favored_enemy">favored enemy</Link>, with a bonus equal to 1/2 her favored terrain bonus.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-dreamstalker-tramautic-spell" data-hash-target><div className="box">Tramautic Spell</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Glib lie</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 11th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A dreamstalker gains <Link to="/feat/traumatic_spell">Traumatic Spell</Link> as a bonus feat.</div></div></div></div>
</>};
const _enigma = {title: "Enigma", jsx: <><h2 id="arc-mesmerist-enigma-enigma">Enigma</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 36</Link><br/>An enigma spends his life dedicated to developing psychic abilities that allow him to operate unnoticed. While the target of a mesmerist's <em>hypnotic stare</em> might not realize that the mesmerist is the source of the strange thoughts invading his mind, an enigma takes that mental obfuscation to a more extreme level. Enigmas often end up serving as master spies and infiltration experts.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-enigma-solipsism-su" data-hash-target><div className="box">Solipsism (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Hypnotic stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">Whenever the enigma uses <em>hypnotic stare</em> on a creature, instead of applying a penalty on the creature's saving throws, the enigma begins to fade from the creature's view. Until the enigma's next turn, the enigma gains the effects of <Link to="/rule/concealment">concealment</Link> against that creature (unless it can see invisible creatures). Starting on the enigma's next turn, he gains the effect of <Link to="/spell/invisibility">invisibility</Link> against that creature. These effects last as long as the enigma continues to use his <em>hypnotic stare,</em> but if he takes an action that would end <em>invisibility,</em> it ends his <em>hypnotic stare</em> immediately. The enigma can reinstate this effect whenever he wishes, but each time it begins with 1 round of concealment.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 8th Level</div></div><div className="abEnd"><div className="box">Attacks that would end <em>invisibility</em> do not end the enigma's <em>hypnotic stare,</em> and after 1 round of concealment, he gains the benefits of <Link to="/spell/greater_invisibility">greater invisibility</Link> against the target of his stare.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">For the purpose of <em>bold stare</em> improvements, the enigma's <em>hypnotic stare</em> always has a penalty of -1.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-enigma-veiled-steps" data-hash-target><div className="box">Veiled Steps</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Consummate liar</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">An enigma gains a bonus to his Stealth checks equal to 1/4 his mesmerist level (minimum +1).</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-enigma-enigmatic-stare-su" data-hash-target><div className="box">Enigmatic Stare (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Painful stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">The target of an enigma's <em>hypnotic stare</em> takes a -4 penalty on Perception checks to notice the enigma.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 8th Level</div></div><div className="abEnd"><div className="box">This penalty increases to - 6.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-palm"><IonIcon icon="/icons/magic-palm.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-enigma-transfer-affliction-su" data-hash-target><div className="box">Transfer Affliction (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Touch treatment</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">The enigma can afflict others with the harmful conditions that he endures. This ability functions as the <em>touch treatment</em> ability, but can only be used to remove harmful conditions from the enigma, not other creatures. In order to remove these harmful effects, the enigma must succeed at a touch attack against another creature. The creature touched gains the chosen harmful effect for whatever duration it would have afflicted the enigma and the effect is removed from the enigma, unless the creature succeeds at a Will save (DC = 10 + 1/2 the enigma's mesmerist level + his Charisma modifier). Using this ability is always a standard action.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 14th Level</div></div><div className="abEnd"><div className="box">The enigma can instead expend one use of <em>touch treatment</em> to replicate the effects of <Link to="/spell/bestow_curse">bestow curse</Link>, delivered as a touch attack as part of using this ability.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box"><em>Transfer affliction</em> is a mind-affecting effect.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-enigma-sneak-attack-ex" data-hash-target><div className="box">Sneak Attack (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Manifold tricks</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An enigma gains the <Link to="/ability/sneak_attack">sneak attack</Link> ability of a rogue, starting at +1d6 damage.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">Sneak attack damage becomes +2d6.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 13th Level</div></div><div className="abEnd"><div className="box">Sneak attack damage increases to +3d6.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 17th Level</div></div><div className="abEnd"><div className="box">Sneak attack damage becomes +4d6.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-enigma-detection-void-su" data-hash-target><div className="box">Detection Void (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Glib lie</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 11th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An enigma can elude <Link to="/main/detect_spells">detection spells</Link> (spells with "detect" in their name). A creature using this sort of magic against the enigma must succeed at a caster level check against a DC equal to 15 + the enigma's class level to succeed (as if the enigma was under the effect of a <Link to="/spell/nondetection">nondetection</Link> spell); failure means the magic fails to detect the enigma, as if he did not exist.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-enigma-absentia-su" data-hash-target><div className="box">Absentia (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Rule minds</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">All creatures adjacent to the enigma subconsciously ignore him. Adjacent creatures are always treated as <Link to="/rule/flat_footed">flat-footed</Link> to the enigma and are not considered to be directly observing the enigma for the purpose of the Stealth skill. This effect ends immediately if the enigma makes a successful attack against any creature, but automatically resumes at the beginning of his next turn.</div></div></div></div>
</>};
const _eyebiter = {title: "Eyebiter", jsx: <><h2 id="arc-mesmerist-eyebiter-eyebiter">Eyebiter</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 36</Link><br/>Mesmerists focus their abilities through the eyes, drawing forth their power as the windows to the mind and soul. Eyebiters take this a step further. An eyebiter's eyes become so infused with psychic might that they can leave the eyebiter's body and move about on their own.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-eyebiter-eyeball-familiar-ex" data-hash-target><div className="box">Eyeball Familiar (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Consummate liar, mesmerist trick gained at 1st level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An eyebiter imbues one of his eyes with limited sentience, so that he can pluck it out and allow it to move on its own. The <em>eyeball familiar</em> functions similarly to the <Link to="/discovery/tumor_familiar">tumor familiar</Link> alchemist discovery except as follows. The <em>eyeball familiar</em> does not have fast healing. The <em>eyeball familiar</em> doesn't resemble an animal, and its size is Fine for a Medium or smaller eyebiter (or one size category larger for every size category the eyebiter is larger than Medium). It has a fly speed of 20 feet (perfect maneuverability) and no physical attacks (though it can still deliver touch spells once the eyebiter has reached 3rd level). The eyeball has a Strength score of 1, a Dexterity score of 12, and a Constitution score of 10. It has no set Hit Die, base saves, or skill ranks of its own, though it uses its master's when a familiar normally would. It doesn't grant its master any familiar bonus, nor can it ever be an <em>improved familiar.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">Whenever the eyebiter's <em>eyeball familiar</em> leaves his body, he is <Link to="/misc/dazzled">dazzled</Link> until it returns (if it is destroyed, the eyebiter loses that eye until he gains the effects of a <Link to="/spell/regenerate">regeneration</Link>). An eyebiter must have at least one eye to use this ability, and an eyebiter with only one eye is <Link to="/misc/blinded">blinded</Link> instead of dazzled until his familiar returns.</div></div></div></div>
<div className="ability p hasSubs"><div className="abIcon"><Link to="/icons/magic-palm"><IonIcon icon="/icons/magic-palm.svg" color="secondary" /></Link><Link to="/icons/smoking-finger"><IonIcon icon="/icons/smoking-finger.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-eyebiter-ocular-occlusion-su" data-hash-target><div className="box">Ocular Occlusion (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">All instances of touch treatment</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">3 + Charisma modifier times/day</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">An eyebiter gains the ability to cloud the sight of others with a melee touch attack. A successful Will save negates the effect (DC = 10 + 1/2 the eyebiter's mesmerist level + his Charisma modifier); this is a mind-affecting ability.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">If the eyebiter chooses to use an <em>ocular occlusion</em> of a lower level than the highest-level effect he has gained, he can instead use a standard action to target a creature within 30 feet with that effect as a ranged touch attack.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-eyebiter-clouded-vision" data-hash-target><div className="box">Clouded Vision</div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The eyebiter can cause the target to become dazzled for 1 minute and suffer a 20% miss chance on all attacks the target makes against opponents within 60 feet. Opponents more than 60 feet away have <Link to="/rule/concealment">total concealment</Link> from the target.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link><Link to="/icons/heart-plus"><IonIcon icon="/icons/heart-plus.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-eyebiter-cause-or-cure-blindness" data-hash-target><div className="box">Cause or Cure Blindness</div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 6th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The eyebiter can blind the target for 1 minute or affect it as per the spell <Link to="/spell/remove_blindness">remove blindness</Link>.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-eyebiter-eyeless-horror" data-hash-target><div className="box">Eyeless Horror</div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 10th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The eyebiter creates a powerful illusion that causes the target's eyes to appear as if they have been ripped out, with blood pouring from the sockets. The target is blinded and <Link to="/misc/shaken">shaken</Link> for 1 round per the eyebiter's mesmerist level, taking 1d4 points of nonlethal damage each round. The target can attempt a second Will save when attacked to negate the shaken effect and the nonlethal damage.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-eyebiter-spellblight" data-hash-target><div className="box">Spellblight</div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 14th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The eyebiter can afflict the target with the <em>ebon eyes</em> or the <em>hemoculysis</em> <Link to="/rule/minor_spellblights">minor spellblight</Link>, or the <em>eldritch cataracts</em> <Link to="/rule/major_spellblights">major spellblight</Link>.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-eyebiter-staring-eye-su" data-hash-target><div className="box">Staring Eye (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Mental potency</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An eyebiter can expend one use of his daily mesmerist tricks to either see through his <em>eyeball familiar</em> as if it were an <Link to="/spell/arcane_eye">arcane eye</Link>, or to use his <em>hypnotic stare</em> (including related abilities like <em>painful stare</em> and <em>bold stare</em>), as well as any <Link to="/umr/gaze">gaze</Link> attack he possesses (like <Link to="/spell/burning_gaze">burning gaze</Link> and <Link to="/spell/eyebite">eyebite</Link>) through his <em>eyeball familiar,</em> as if he were at its location.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-eyebiter-omnivisual-ex" data-hash-target><div className="box">Omnivisual (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Glib lie</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 11th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">An eyebiter's roving <em>eyeball familiar</em> is constantly watching in all directions. As long as his <em>eyeball familiar</em> is outside his body and near enough to see the same things (such as being in the same room), the eyebiter gains <Link to="/umr/all_around_vision">all-around vision</Link> and cannot be <Link to="/rule/flanked">flanked</Link>.</div></div></div></div>
</>};
const _fey_trickster = {title: "Fey Trickster", jsx: <><h2 id="arc-mesmerist-fey_trickster-fey-trickster">Fey Trickster</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 37</Link><br/>Most mesmerists draw psychic power from the Astral Plane, but a few gain their powers in an unusual way: from a brush with the fey. Prisoner-guests of the fey, these souls find themselves changed when they return to the mortal world, infused with the eldritch energy of their former hosts.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/skills"><IonIcon icon="/icons/skills.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-fey_trickster-undefined" data-hash-target><div className="box">Class Skills</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Class skills</div></div></div><div className="abPair"><div className="abStart"><div className="box">New Class Skills</div></div><div className="abEnd"><div className="box"><Link to="/skill/handle_animal">Handle Animal</Link> (CHA), <Link to="/skill/knowledge_nature">Knowledge (nature)</Link> (INT), <Link to="/skill/survival">Survival</Link> (WIS)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Removed Skills</div></div><div className="abEnd"><div className="box">Appraise, Knowledge (dungeoneering), Profession</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-fey_trickster-natures-lure" data-hash-target><div className="box">Nature's Lure</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Spellcasting</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">Rather than casting psychic spells from the mesmerist spell list, a fey trickster casts divine spells drawn from the <Link to="/main/spells_hunter">druid and ranger spell lists</Link>, in just the same way as a hunter does. This means that she gains orisons instead of knacks. This doesn't change her number of spells per day or spells known. The fey trickster's mesmerist spells and spell-like abilities count as if they were fey spell-like abilities for the purpose of effects like <em>resist nature's lure</em> that apply against fey spell-like abilities.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-fey_trickster-feytouched-ex" data-hash-target><div className="box">Feytouched (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Towering ego</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A fey trickster's time with the fey has granted her strange powers, as well as resistance to further fey mischief. The fey trickster gains the druid's <Link to="/ability/resist_natures_lure">resist nature's lure</Link> and <Link to="/ability/woodland_stride">woodland stride</Link> abilities, and she counts as both <Link to="/type/fey">fey</Link> and her original creature type for the purpose of spells and effects.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-fey_trickster-fey-veil-sp-su" data-hash-target><div className="box">Fey Veil (Sp, Su)</div><div className="flavor">A fey trickster's physical form begins to shift, as she gains some of the impossible allure of the fey. At the same time, she begins able to use <em>fey veils</em> to assist herself and her allies in befuddling and bewitching their opponents.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch treatment</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">3 + Charisma modifier times/day</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">Using the ability is a <strong className="hl">standard action</strong> (or a <strong className="hl">swift action</strong> if the fey trickster calls up a <em>veil</em> over herself). If she targets another ally, the fey trickster must be able to contact the ally bodily, usually with a kiss. When she uses her <em>fey veil,</em> the fey trickster subtly alters the appearance and aura of her target, granting one of the powers allowed by her mesmerist level.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 3rd Level</div></div><div className="abEnd"><div className="box">She can grant the ally a +2 circumstance bonus on her choice of Diplomacy, Intimidate, or Handle Animal checks for 1 minute.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">She can change the ally's form so thoroughly that the ally gains a +10 bonus on Disguise checks until the next sunrise (similar to the bonus from <Link to="/spell/disguise_self">disguise self</Link>, but it also disguises touch and sound, and it doesn't allow a saving throw to disbelieve).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">The fey trickster can make the ally and her aura so attractive or repulsive for 10 minutes that the <em>veil</em> automatically adjusts the moods of those who see the ally and fail their saving throw, as <Link to="/spell/telempathic_projection">telempathic projection</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 14th Level</div></div><div className="abEnd"><div className="box">A fey trickster can create a <em>veil</em> so powerful that it fools even reality, granting the full effects of both the 6th-level <em>fey veil</em> and <Link to="/spell/alter_self">alter self</Link> to the target for 1 hour. Each of these abilities, even the 14th-level ability, is an illusion and glamer effect, though the last ability counts as a size-changing <Link to="/spelldef/polymorph">polymorph</Link> effect for the limit of only one polymorph or size-changing effect on a creature.</div></div></div></div>
<div className="ability p hasSubs"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-fey_trickster-one-with-the-fey" data-hash-target><div className="box">One with the Fey</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Rule minds</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A fey trickster fully transforms into a fey, though she can still choose to count as her original creature type as well whenever it would be advantageous to her (such as if she is a humanoid and wishes to be affected by <Link to="/spell/reduce_person">reduce person</Link>). She gains low-light vision as well as an additional ability depending on which type of fey she chooses to most closely associate with. Some examples follow.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-fey_trickster-erlking" data-hash-target><div className="box">Erlking</div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">The fey trickster is constantly under the effects of <Link to="/spell/haste">haste</Link>.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-fey_trickster-nymph" data-hash-target><div className="box">Nymph</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The fey trickster gains the <Link to="/monster/nymph">nymph's</Link> <em>unearthly grace</em> ability</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-fey_trickster-quickling" data-hash-target><div className="box">Quickling</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The fey trickster gains the <Link to="/monster/quickling">quickling's</Link> <em>supernatural speed</em> ability.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/mailed-fist"><IonIcon icon="/icons/mailed-fist.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-fey_trickster-rusalka" data-hash-target><div className="box">Rusalka</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The fey trickster gains the <Link to="/monster/rusalka">rusalka's</Link> <em>tresses</em> ability and four tress primary <Link to="/umr/natural_attacks">natural attacks</Link> similar to those of a rusalka.</div></div></div></div>
</>};
const _gaslighter = {title: "Gaslighter", jsx: <><h2 id="arc-mesmerist-gaslighter-gaslighter">Gaslighter</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 60</Link><br/>A gaslighter takes joy in others' suffering, delighting in driving them to madness.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/hazard-sign"><IonIcon icon="/icons/hazard-sign.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-gaslighter-alignment" data-hash-target><div className="box">Alignment</div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">A gaslighter must be of an evil alignment. A gaslighter who becomes nonevil cannot gain new levels as a mesmerist but retains all his class abilities.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-gaslighter-consummate-cruelty" data-hash-target><div className="box">Consummate Cruelty</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Consummate liar</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A gaslighter gains a bonus equal to 1/2 his mesmerist level (minimum 1) on Intimidate checks.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A gaslighter can take <Link to="/feat/improved_dirty_trick">Improved Dirty Trick</Link> and <Link to="/feat/greater_dirty_trick">Greater Dirty Trick</Link> without having <Link to="/feat/combat_expertise">Combat Expertise</Link> or an Intelligence score of 13. He can also ignore those two prerequisites for other feats that have Improved Dirty Trick or Greater Dirty Trick as a prerequisite.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-gaslighter-horrid-mask-su" data-hash-target><div className="box">Horrid Mask (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch treatment (minor)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Painful stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">3 + Charisma modifier times/day</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">A gaslighter can implant a maddening phantasm in the mind of the target of his <em>hypnotic stare,</em> causing the target to perceive its own reflection as corrupted in some disturbing way. This is a mind-affecting fear effect, and there is no saving throw. The target is simultaneously captivated and horrified by the sight of its own reflection, and in any round in which the target can see itself in a mirror within 30 feet, the gaslighter can trigger his <em>painful stare</em> against the target without dealing damage. This is a <Link to="/umr/gaze">gaze</Link> attack, and the creature can avert its eyes to attempt to avoid it.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">Any creature holding a visible mirror that attempts to demoralize the target can choose to add the gaslighter's Charisma modifier to its Intimidate check instead of its own. <em>Horrid mask</em> lasts until that particular <em>hypnotic stare</em> ends (often when the target moves away from a mirror). The gaslighter can use this ability a number of times per day equal to 3 + his Charisma modifier.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-gaslighter-phantasmal-force-su" data-hash-target><div className="box">Phantasmal Force (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch treatment (moderate)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 6th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A gaslighter can force the target of his <em>horrid mask</em> ability to recoil from its reflection. Whenever the gaslighter uses <em>horrid mask,</em> if an affected target begins its turn adjacent to a mirror, it must succeed at a Will save (DC = 10 + 1/2 the gaslighter's mesmerist level + his Charisma modifier) or be compelled to either flee from the mirror (or the creature holding it) to beyond 30 feet or attempt to destroy the mirror (or the creature holding it). This is a gaze attack, and the target can attempt to avert its eyes.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-gaslighter-phantasmal-foes-su" data-hash-target><div className="box">Phantasmal Foes (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch treatment (greater)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 10th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">A gaslighter can spend one use of his <em>horrid mask</em> ability to convince the target of his <em>hypnotic stare</em> that it is surrounded by foes only it can see. The target is treated as <Link to="/rule/flanked">flanked</Link> for any melee attacks against it until the <em>hypnotic stare</em> ends.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">The gaslighter can use either this ability or <em>horrid mask</em> during a particular <em>hypnotic stare,</em> but not both at once. This is a mind-affecting fear effect.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-gaslighter-corosion-of-sanity-su" data-hash-target><div className="box">Corosion of Sanity (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch treatment (break enchantment)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 14th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">Whenever a creature fails its initial saving throw against a gaslighter's single-target mind-affecting effect, the target also takes 1 point of <Link to="/rule/wisdom_damage">Wisdom damage</Link>. This has no effect on abilities that don't allow a saving throw or affect multiple targets or an area.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">If using <Link to="/rule/sanity">the sanity system</Link>, the target takes 2 points of sanity damage instead.</div></div></div></div>
</>};
const _hate_monger = {title: "Hate-Monger", jsx: <><h2 id="arc-mesmerist-hate_monger-hate-monger">Hate-Monger</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 61</Link><br/>Hate-mongers are xenophobic and judgmental rabblerousers who whip up mobs against enemies real or imagined.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/hazard-sign"><IonIcon icon="/icons/hazard-sign.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-hate_monger-alignment" data-hash-target><div className="box">Alignment</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A hate-monger must be of a nongood alignment. A hate-monger who becomes good cannot gain new levels as a mesmerist but retains all his class abilities.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/spell-book"><IonIcon icon="/icons/spell-book.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-hate_monger-mental-manipulator-ex" data-hash-target><div className="box">Mental Manipulator (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Consummate liar</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Mesmerist tricks</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A hate-monger masters a broad repertoire of emotional corruption. At 1st level, he adds one spell from the 1st-level spells below to his spells known. When he would gain a new mesmerist trick, he can learn additional spells instead, adding two of the following spells of a level he can currently cast to his spells known. When he casts a spell he learns in this way, he increases the duration as if his caster level were 1 higher.</div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">1st</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/cause_fear">Cause fear</Link>, <Link to="/spell/compel_hostility">compel hostility</Link>, <Link to="/spell/delusional_pride">delusional pride</Link>, <Link to="/spell/demand_offering">demand offering</Link>, <Link to="/spell/forbid_action">forbid action</Link>, <Link to="/spell/lesser_confusion">lesser confusion</Link>, <Link to="/spell/murderous_command">murderous command</Link>, <Link to="/spell/scare">scare</Link>, <Link to="/spell/sow_thought">sow thought</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">2nd</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/aversion">Aversion</Link>, <Link to="/spell/paranoia">paranoia</Link>, <Link to="/spell/rage">rage</Link>, <Link to="/spell/unadulterated_loathing">unadulterated loathing</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">3rd</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/confusion">Confusion</Link>, <Link to="/spell/crushing_despair">crushing despair</Link>, <Link to="/spell/curse_of_disgust">curse of disgust</Link>, <Link to="/spell/fear">fear</Link>, <Link to="/spell/instant_enemy">instant enemy</Link>, <Link to="/spell/malicious_spite">malicious spite</Link>, <Link to="/spell/smug_narcissism">smug narcissism</Link>, <Link to="/spell/spite">spite</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">4th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/envious_urge">Envious urge</Link>, <Link to="/spell/feast_on_fear">feast on fear</Link>, <Link to="/spell/greater_forbid_action">greater forbid action</Link>, <Link to="/spell/modify_memory">modify memory</Link>, <Link to="/spell/utter_contempt">utter contempt</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">5th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/foe_to_friend">Foe to friend</Link>, <Link to="/spell/foster_hatred">foster hatred</Link>, <Link to="/spell/song_of_discord">song of discord</Link>, <Link to="/spell/repress_memory">repress memory</Link>, <Link to="/spell/unwilling_shield">unwilling shield</Link>, <Link to="/spell/vengeful_outrage">vengeful outrage</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">6th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/eyebite">Eyebite</Link>, <Link to="/spell/insanity">insanity</Link>, <Link to="/spell/overwhelming_presence">overwhelming presence</Link>, <Link to="/spell/symbol_of_persuasion">symbol of persuasion</Link></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 5th Level</div></div><div className="abEnd"><div className="box">The save DC is increased by 1 for creatures of his favored enemy type (see <em>xenophobe</em> below).</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-hate_monger-insidious-hatred-su" data-hash-target><div className="box">Insidious Hatred (Su)</div><div className="flavor">A hate-monger can sow hatred and strife under the pretense of assisting others.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Touch treatment</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">He can use his <em>touch treatment</em> only on others, but as part of the action of using <em>touch treatment,</em> he can cast any targeted spell from the <em>mental manipulator</em> list that does not have a range of "personal" and has a casting time of 1 standard action or less, targeting only the creature that receives his <em>touch treatment.</em> The target creature takes a -2 penalty on its saving throw and to its spell resistance against the spell.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">That creature doesn't realize the hatemonger has cast a spell, and considers any manifestations to be part of the <em>touch treatment.</em> Other creatures notice as normal.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-hate_monger-xenophobe-ex" data-hash-target><div className="box">Xenophobe (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Mental potency, manifold tricks</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A hate-monger can choose one <Link to="/ability/favored_enemy">favored enemy</Link>, as per the <Link to="/class/ranger">ranger</Link> class feature. His favored enemy bonus begins at +2, but he does not gain additional favored enemies. His favored enemy bonus also applies on Intimidate checks against his favored enemy.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">The bonus becomes +4.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 13th Level</div></div><div className="abEnd"><div className="box">The bonus increases to +6.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 17th Level</div></div><div className="abEnd"><div className="box">The bonus becomes +8.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-hate_monger-out-for-blood-ex" data-hash-target><div className="box">Out for Blood (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">7th-level bold stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 7th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">When a creature takes extra damage from the hate-monger's <em>painful stare,</em> it also takes 1 point of <Link to="/rule/bleed">bleed</Link> damage (or 1 point of bleed damage per 1d6 points of damage dealt by the <em>painful stare</em> if the hatemonger damages the target himself). This bleed damage does not stack with itself or other sources of bleed damage.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-hate_monger-insidious-emotions-su" data-hash-target><div className="box">Insidious Emotions (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Glib lie</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 11th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">The power of a hatemonger's psychic hold becomes more difficult to detect or to break. The DC of Sense Motive checks to notice if a creature is under the effects of his enchantments with the emotion descriptor increases by 5 (if he also has the <Link to="/feat/subtle_enchantments">Subtle Enchantments</Link> feat, the effects stack), as does the DC to identify his emotion spells. Magical divinations can detect his emotion effects only if the caster succeeds at a caster level check (DC = 11 the hate-monger's mesmerist level) as if the affected creatures were the subject of <Link to="/spell/nondetection">nondetection</Link>.</div></div></div></div>
</>};
const _material_manipulator = {title: "Material Manipulator", jsx: <><h2 id="arc-mesmerist-material_manipulator-material-manipulator">Material Manipulator</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 18</Link><br/>Rather than waste time limiting himself to ruling minds, a material manipulator forces his whims upon reality and uses his magic to ensure that those around him comply with his demands.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/spell-book"><IonIcon icon="/icons/spell-book.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-material_manipulator-manipulator-spells" data-hash-target><div className="box">Manipulator Spells</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Consummate liar, mesmerist trick gained at 2nd level, manifold tricks</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Spellcasting</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A material manipulator casts psychic spells drawn from the mesmerist spell list and augmented by a select list of <Link to="/main/spells_wizard">sorcerer/wizard spells</Link>. All <Link to="/main/spells_illusion">illusion</Link> (glamer), illusion (shadow), and <Link to="/main/spells_transmutation">transmutation</Link> spells of 6th level and lower are considered to be part of the material manipulator's spell list. These are psychic spells.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-material_manipulator-revision-su" data-hash-target><div className="box">Revision (Su)</div><div className="flavor">A material manipulator can revise a creature's body to change its appearance.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch treatment, rule minds</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">3 + Charisma modifier times/day</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">Using <em>revision</em> is a <strong className="hl">standard action</strong> (or a <strong className="hl">swift action</strong> if the material manipulator uses it on himself), and the material manipulator must be able to touch his target. An unwilling target must succeed at a Fortitude save (DC = 10 + half the material manipulator's mesmerist level + his Charisma modifier) to negate the effect. This effect lasts for 10 minutes per mesmerist level.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 3rd Level</div></div><div className="abEnd"><div className="box">The material manipulator can adjust the target's height and weight, increasing it or decreasing it to any height or weight within the standard range for creatures of the target's <Link to="/rule/height_and_weight">type and size category</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">He can adjust the target's gender, physical traits (such as nose size, fingernail length, and foot shape), and pigmentation (including eye, hair, and skin color) to any natural variation for creatures of the target's type (and heritage, if applicable).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">He can adjust the target's age, rewinding the target's age to as young as a young adult (approximately 8 years old for a human) or progressing it to as old as venerable. This causes the target to gain aging bonuses and penalties and adjust its size <Link to="/rule/age">as appropriate for its new age</Link>, but doesn't confer any other benefits gained from aging (such as additional racial Hit Dice, supernatural abilities, and so on). The effects of <em>revision</em> now last for 1 hour per mesmerist level.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 14th Level</div></div><div className="abEnd"><div className="box">He can adjust the target's type or subtype, as per <Link to="/spell/polymorph">polymorph</Link>. This <em>revision</em> only lasts 1 minute per mesmerist level.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 20th Level</div></div><div className="abEnd"><div className="box">He can instead adjust the target's type as per <Link to="/spell/greater_polymorph">greater polymorph</Link>. The effect of <em>revision</em> lasts indefinitely, or 10 minutes per mesmerist level if the material manipulator uses it as <em>greater polymorph</em> and causes the target to assume a form with a different type than its true form.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">The mesmerist can dismiss this effect as a <strong className="hl">free action</strong>. This ability is a polymorph effect, and the subject of a <em>revision</em> cannot end the effect early by any means unless the material manipulator permits it. The material manipulator can stack multiple adjustments from this ability into the same polymorph effect - for instance, a 14th-level material manipulator can adjust himself into an orc, reduce his age to that of a young adult, give himself large feet and a bulbous nose, and change his gender. Clothing and equipment worn by the target is not affected by this effect - gear does not resize to suit the wearer's new form, nor does it merge into her body. Gear unable to be worn or wielded as a result of this effect falls to the ground in the wearer's space.</div></div></div></div>
</>};
const _mindwyrm_mesmer = {title: "Mindwyrm Mesmer", jsx: <><h2 id="arc-mesmerist-mindwyrm_mesmer-mindwyrm-mesmer">Mindwyrm Mesmer</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_dragons">Legacy of Dragons pg. 13</Link><br/>While most mesmerists are subtle and manipulative schemers, mindwyrm mesmers emulate the confidence, swagger, and fear inspired by dragons to bully and browbeat others into obedience. These dragon-inspired psychic magic-users typically employ draconic imagery in their dress and the manifestations of their powers.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-mindwyrm_mesmer-innate-coercion" data-hash-target><div className="box">Innate Coercion</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Consummate liar</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A mindwyrm mesmer gains a bonus equal to 1/2 his mesmerist level (minimum 1) on Intimidate checks. In addition, a mindwyrm mesmer never takes penalties on Intimidate checks for being smaller than his target.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/tornado-discs"><IonIcon icon="/icons/tornado-discs.svg" color="secondary" /></Link><Link to="/icons/barbed-arrow"><IonIcon icon="/icons/barbed-arrow.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-mindwyrm_mesmer-phantasmagorical-breath-su" data-hash-target><div className="box">Phantasmagorical Breath (Su)</div><div className="flavor">A mindwyrm mesmer has learned to mimic a <Link to="/family/true_dragon">true dragon's</Link> destructive breath using his psychic ability.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Painful stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">Charisma modifier times/day (minimum 1)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">A mindwyrm mesmer can unleash his phantasmagoric breath in either a 30-foot cone or a 60-foot line. The breath induces a psychosomatic response in creatures caught in the area, dealing 1d6 points of energy damage. The mindwyrm mesmer selects the type of energy damage this deals (acid, cold, electricity, or fire) when this ability is first gained; once made, this choice can't be changed. Creatures affected can attempt a Will save (DC = 10 + 1/2 the mindwyrm mesmer's mesmerist level + his Charisma modifier) to realize the true nature of the attack, which negates all damage. This is a mind-affecting effect.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 3rd Level</div></div><div className="abEnd"><div className="box">The energy damage becomes becomes 2d6.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 5th Level</div></div><div className="abEnd"><div className="box">The energy damage becomes increases to 3d6.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 7th Level</div></div><div className="abEnd"><div className="box">The energy damage becomes becomes 4d6.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">The energy damage becomes increases to 5d6.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">The energy damage becomes becomes 6d6.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 13th Level</div></div><div className="abEnd"><div className="box">The energy damage becomes increases to 7d6.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 15th Level</div></div><div className="abEnd"><div className="box">The energy damage becomes becomes 8d6.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 17th Level</div></div><div className="abEnd"><div className="box">The energy damage becomes increases to 9d6.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 19th Level</div></div><div className="abEnd"><div className="box">The energy damage becomes becomes 10d6.</div></div></div></div>
<div className="ability p hasSubs"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-mindwyrm_mesmer-draconic-trick-su" data-hash-target><div className="box">Draconic Trick (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">The following new trick can be selected by a mindwyrm mesmer.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-mindwyrm_mesmer-threatening-mien" data-hash-target><div className="box">Threatening Mien</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The subject's actions appear to be lethal in the extreme. A mindwyrm mesmer can trigger this trick when the subject moves adjacent to an enemy. Enemies adjacent to the subject take a -4 penalty on attacks against targets other than the subject. This trick lasts for 1 round per mindwyrm mesmer's mesmerist level.</div></div></div></div>
<div className="ability p hasSubs"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-mindwyrm_mesmer-masterful-draconic-trick-su" data-hash-target><div className="box">Masterful Draconic Trick (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box">At 12th Level</div></div><div className="abEnd"><div className="box">The following new masterful trick can be selected by a mindwyrm mesmer of 12th level or higher.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-mindwyrm_mesmer-frightful-countenance" data-hash-target><div className="box">Frightful Countenance</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The subject's appearance changes into that which frightens an attacker to the core. The mindwyrm mesmer can trigger this trick when the subject is targeted by an attack or by a spell that requires an attack roll. The attacker must succeed at a Will save or the attack misses and the attacker immediately becomes <Link to="/misc/shaken">shaken</Link> for 1d4 rounds. This is a mind-affecting fear effect.</div></div></div></div>
</>};
const _projectionist = {title: "Projectionist", jsx: <><h2 id="arc-mesmerist-projectionist-projectionist">Projectionist</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 18</Link><br/>Not content to simply command others from afar, a projectionist is able to use his mesmerizing powers to utterly dominate other creatures and objects by projecting his spirit from his body.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link><Link to="/icons/spell-book"><IonIcon icon="/icons/spell-book.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-projectionist-spells" data-hash-target><div className="box">Spells</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Spellcasting</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A projectionist's psychic powers manifest in an almost predictable manner, making them less versatile than other spellcasters. At each of the indicated levels, a projectionist must choose the indicated spell to learn - he cannot choose other spells. The spells that a projectionist must learn (and the level at which he must choose them) are shown below.</div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">4th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/enter_image">Enter image</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">7th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/lesser_object_possession">Lesser object possession</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">10th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/riding_possession">Riding possession</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">13th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/object_possession">Object possession</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">16th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/greater_object_possession">Greater object possession</Link> (as a 6th-level spell)</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-projectionist-implant-consciousness-su" data-hash-target><div className="box">Implant Consciousness (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Mesmerist tricks gained at 4th and 8th levels</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 4th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A projectionist can spend one use of his mesmerist trick ability to create a psychic link between himself and one object that bears his likeness, such as a painting or a statue. This functions in all ways like implanting a mesmerist trick in a creature, except the target is an object. The projectionist can trigger the trick as a <strong className="hl">standard action</strong> at any time - upon doing so, his consciousness leaves his body and fills the target object, functioning as described by the "filling an image with your consciousness" use of the <em>enter image</em> spell. Use the projectionist's mesmerist level as the spell's caster level. While filling an image with his consciousness, the projectionist can use and maintain his <em>hypnotic stare</em> on opponents, and can also trigger his <em>painful stare.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 8th Level</div></div><div className="abEnd"><div className="box">He can also use any purely mental action (including casting psychic spells) while filling an object with his consciousness.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">Once he implants this trick in an object, the projectionist can fill the target with his consciousness whenever he pleases, regardless of distance or whether he is on the same plane as his target. Once he stops concentrating on maintaining the <em>enter image</em> effect, his consciousness returns to his body and he cannot fill the target with his consciousness again until he implants another mesmerist trick in that object.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-projectionist-hidden-presence" data-hash-target><div className="box">Hidden Presence</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Mental potency</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A projectionist gains <Link to="/feat/hidden_presence">Hidden Presence</Link> as a bonus feat. He doesn't need to meet the feat's prerequisites. He benefits from Hidden Presence and feats that list Hidden Presence as a prerequisite while possessing objects (as with <em>object possession</em>) or while filling an object with his consciousness (as described in the <em>enter image</em> spell), as well as when he possesses creatures, provided the feat is applicable. For instance, <Link to="/feat/intrusive_presence">Intrusive Presence</Link> cannot be used to read the mind of an inanimate object possessed via <em>enter image</em> or <em>object possession,</em> as objects possess no minds to be read.</div></div></div></div>
</>};
const _spirit_walker = {title: "Spirit Walker", jsx: <><h2 id="arc-mesmerist-spirit_walker-spirit-walker">Spirit Walker</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 97</Link><br/>Some mesmerists specialize in dominating and controlling undead rather than the living.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/spell-book"><IonIcon icon="/icons/spell-book.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-spirit_walker-spells" data-hash-target><div className="box">Spells</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Spell list</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">A spirit walker adds additional spells to his spell list at the spell levels indicated. He can choose these as spells known, but doesn't gain them automatically.</div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">1st</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/hide_from_undead">Hide from undead</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">2nd</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/command_undead">Command undead</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">3rd</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/halt_undead">Halt undead</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">4th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/speak_with_haunt">Speak with haunt</Link></div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-spirit_walker-undead-inception-su" data-hash-target><div className="box">Undead Inception (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Consummate liar, mental potency</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A spirit walker can affect undead creatures with his <em>hypnotic stare</em> as the <em>psychic inception</em> <Link to="/ability/stares">bold stare</Link> ability. This allows him to affect only undead; he must actually choose the <em>psychic inception bold stare</em> improvement if he wants to also affect other mindless creatures.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 3rd Level</div></div><div className="abEnd"><div className="box">When the spirit walker uses this ability, undead targets don't receive a saving throw bonus (if they did to begin with), have only a 25% chance of ignoring the spirit walker's mind-affecting spells and abilities, and no longer need to be under the spirit walker's gaze to be affected.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 5th Level</div></div><div className="abEnd"><div className="box">When the spirit walker uses his mind-affecting spells and abilities, they affect all undead normally, with no chance of failure.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-spirit_walker-continued-animation-su" data-hash-target><div className="box">Continued Animation (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">3rd- and 14th-level touch treatments</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">1 time/day per three mesmerist levels</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Immediate Action</div></div><div className="abEnd"><div className="box">When a spirit walker is using <em>hypnotic stare</em> on a humanoid target and the target dies, the spirit walker can force the target's soul to remain in the body. The spirit walker can then control the target as if using <Link to="/spell/dominate_person">dominate person</Link> for a number of rounds equal to 1/2 the spirit walker's class level. The creature gains a number of <Link to="/rule/temporary_hit_points">temporary hit points</Link> equal to 2 &times; the spirit walker's class level and continues acting as though it were alive and conscious until it loses those temporary hit points or the duration expires. During this time, the creature counts as undead, but it can't be healed by negative energy.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 14th Level</div></div><div className="abEnd"><div className="box">The spirit walker can apply this ability to any type of target as if using <Link to="/spell/dominate_monster">dominate monster</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">The target receives a Will saving throw (DC = 10 + 1/2 the spirit walker's class level + his Charisma modifier) to avoid this effect and die normally. This ability ends immediately if at any point the target's body is completely destroyed (such as by <Link to="/spell/disintegrate">disintegrate</Link>) or restored to life.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-spirit_walker-command-undead-su" data-hash-target><div className="box">Command Undead (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">6th- and 10th-level touch treatments</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 6th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A spirit walker gains <Link to="/feat/command_undead">Command Undead</Link> as a bonus feat. A spirit walker can use Command Undead a number of times per day equal to 1 + his Charisma modifier (minimum 1), using his mesmerist level as his cleric level.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">The DC to resist this effect increases by 2.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-spirit_walker-master-of-the-dead-su" data-hash-target><div className="box">Master of the Dead (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Rule minds</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A spirit walker gains mastery of the undead. Once per day, a spirit walker can use <Link to="/spell/control_undead">control undead</Link> as a spell-like ability on one target. If that creature fails its saving throw and has 20 or fewer Hit Dice, it falls permanently under the spirit walker's control until the spirit walker dies. A creature that fails its save but has more than 20 HD suffers the effect of <em>command undead.</em> A creature that succeeds at its save can't be affected by <em>master of the dead</em> for 24 hours. A spirit walker can control only one undead creature in this fashion at a time. If he permanently controls a new undead creature, the previous one is set free.</div></div></div></div>
</>};
const _thought_eater = {title: "Thought Eater", jsx: <><h2 id="arc-mesmerist-thought_eater-thought-eater">Thought Eater</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 38</Link><br/>Mesmerists that learn to pierce deep into the minds of their victims are known as thought eaters, dangerous individuals capable of devouring thoughts and assuming the knowledge those notions represent for themselves.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-thought_eater-assume-identity-su" data-hash-target><div className="box">Assume Identity (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Consummate liar</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">When a thought eater targets a creature with his <em>hypnotic stare</em> ability, the thought eater gains a bonus on Disguise checks to appear as that creature. This bonus is equal to the thought eater's mesmerist level, and lasts for 24 hours, or until he uses his <em>hypnotic stare</em> ability on a different creature.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-thought_eater-assume-morality-su" data-hash-target><div className="box">Assume Morality (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Towering ego</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The thought eater's alignment matches that of the target of his <em>assume identity</em> ability for the purposes of spells and effects that discern alignment. This includes any increase to alignment aura strength from class features, such as a cleric's aura ability.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-thought_eater-assume-knowledge-su" data-hash-target><div className="box">Assume Knowledge (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch treatment</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The thought eater can choose one Knowledge skill possessed by the target of his <em>hypnotic stare.</em> He uses the target's number of ranks in that skill, instead of his own, to calculate his bonus (but not for other purposes, such as meeting the prerequisites of feats) to a maximum number of ranks equal to his mesmerist level. This ability lasts for 24 hours or until he uses his <em>hypnotic stare</em> ability on a different creature.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-thought_eater-consume-identity-su" data-hash-target><div className="box">Consume Identity (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Rule minds</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Free Action</div></div><div className="abEnd"><div className="box">When the thought eater kills a target of his <em>hypnotic stare,</em> he can choose to entirely consume the creature's identity, mind, body, and soul. The target's corpse dissolves and as long as the thought eater lives, the target of <em>consume identity</em> cannot be brought back from the dead until the thought eater releases the identity (a <strong className="hl">standard action</strong>) or uses <em>consume identity</em> on another target. The creature's soul can also be released by a <Link to="/spell/wish">wish</Link> or <Link to="/spell/miracle">miracle</Link> (which ends the effect of <em>consume identity</em>). When the thought eater has consumed an identity, all divination spells identify him as (and consider him to be) the creature whose identity he consumed rather than himself. This ability fools any spell short of <Link to="/spell/discern_location">discern location</Link>. <em>Discern location</em> pinpoints the thought eater's location, whenever either the thought eater or the consumed creature is the target of that spell.</div></div></div></div>
</>};
const _toxitician = {title: "Toxitician", jsx: <><h2 id="arc-mesmerist-toxitician-toxitician">Toxitician</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 98</Link><br/>Toxiticians forgo the mesmerist's stare, instead combining their psychic power with their alchemical knowledge to craft injections that torment their foes and bolster themselves and their allies.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-toxitician-deft-fingers-ex" data-hash-target><div className="box">Deft Fingers (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Consummate liar</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A toxitician adds 1/2 his class level (minimum 1) as a bonus on all Sleight of Hands checks.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link><Link to="/icons/magic-palm"><IonIcon icon="/icons/magic-palm.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-toxitician-injections-su" data-hash-target><div className="box">Injections (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Hypnotic stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box"><p>The toxitician uses his skill with alchemy and his own psychic powers to create injections. The toxitician can create a number of injections per day equal to his mesmerist level + his Charisma modifier. It takes 1 hour to create the injections. An injection is inert until the toxitician attempts to use it, taking a <strong className="hl">swift action</strong> to infuse it with his psychic power to activate it.</p>
<p>Using an injection requires taking a <strong className="hl">standard action</strong> to attempt a melee touch attack. If the attack hits, the target of an injection takes a -2 penalty on its Will saving throws for a number of minutes equal to 1/2 the toxitican's class level (minimum 1). The toxitician can simultaneously attempt a DC 20 Sleight of Hand check to inject the target surreptitiously. If the toxitician uses Sleight of Hand, the target can attempt a Perception check to detect the attempt, opposed by the Sleight of Hand check result, but detecting the attempt doesn't prevent the creature from being injected. Whenever the toxitician uses Sleight of Hand to administer one of his injections, he can implant it rather than injecting it and then trigger the effect of the injection at a later time. At any point before he regains his injections, the toxitician can trigger an implanted injection as a <strong className="hl">free action</strong>. The toxitician must be within medium range (100 feet + 10 feet per mesmerist level) of the target of the implanted injection.</p>
<p>If either the melee touch attack or the Sleight of Hand check (if attempted) fails, the injection isn't delivered but can still be used again - once activated, it remains potent for 1 day. An injection that hasn't been administered becomes inert if it leaves the toxitician's possession, reactivating as soon as it returns to his keeping.</p>
<p>The penalties from multiple injections don't stack, nor do the penalties from injections stack with penalties from mesmerist <em>stares</em> or witches' <Link to="/hex/evil_eye">evil eye</Link> hexes. Injections are mind-affecting effects.</p>
</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 8th Level</div></div><div className="abEnd"><div className="box">The penalty on Will saves becomes -3.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-toxitician-painful-injection-su" data-hash-target><div className="box">Painful Injection (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Painful stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The toxitician's injection causes intense pain. This increases the damage the subject takes in the same way as the mesmerist's <em>painful stare</em> class feature. This extra damage is dealt automatically, without being triggered by the toxitician, but doesn't increase when the toxitician damages the target and can still be dealt only once per round.</div></div></div></div>
<div className="ability p hasSubs"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-toxitician-injection-improvement-su" data-hash-target><div className="box">Injection Improvement (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Bold stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A toxitician can select one improvement (from those listed below) to add to his injections. The toxitician doesn't have to select the improvements when he prepares his injections at the start of the day; the choice is made as part of the <strong className="hl">swift action</strong> to activate the injection. The target can attempt a Fortitude saving throw to resist an injection with an improvement added to it. The DC is 10 + 1/2 the toxitician's class level + the toxitician's Charisma modifier. On a successful save, the target still takes the penalty on its Will saving throws, but not the effects of the improvement.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Free Action</div></div><div className="abEnd"><div className="box">A toxitician can sacrifice one use of his injections to increase the DC of another injection by 2.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 7th Level</div></div><div className="abEnd"><div className="box">He can select a 2nd improvement.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">He can select a 3rd improvement.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 15th Level</div></div><div className="abEnd"><div className="box">He can select a 4th improvement.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 19th Level</div></div><div className="abEnd"><div className="box">He can select a 5th improvement.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">The toxitician can't choose the same improvement more than once.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-toxitician-ability-decrease" data-hash-target><div className="box">Ability Decrease</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The target takes a -2 penalty to one ability score of the toxitician's choosing.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">The penalty becomes -4.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-toxitician-excruciating" data-hash-target><div className="box">Excruciating</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The extra damage from <em>painful injection</em> increases by an amount equal to 2 points + 1 point per 3 mesmerist levels the toxitician possesses.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-toxitician-fortitude-decrease" data-hash-target><div className="box">Fortitude Decrease</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The target's immune system weakens, imposing a -2 penalty on Fortitude saving throws.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">The penalty becomes -4.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-toxitician-natural-armor-decrease" data-hash-target><div className="box">Natural Armor Decrease</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The target's skin becomes looser, decreasing its natural armor (if any) by 2.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">Its natural armor bonus instead decreases by 4.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-toxitician-reflex-decrease" data-hash-target><div className="box">Reflex Decrease</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The target's body becomes stiffer, imposing a -2 penalty on the target's Reflex saving throws.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">The penalty becomes -4.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-toxitician-slow" data-hash-target><div className="box">Slow</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The target's actions become sluggish, reducing its base movement by 10 feet and imposing a -1 penalty on attack rolls.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">The penalty on attack rolls becomes -2.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/heart-plus"><IonIcon icon="/icons/heart-plus.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-toxitician-treatment-vials-su" data-hash-target><div className="box">Treatment Vials (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Touch treatment</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A toxitician can create treatment vials when he creates his injections for the day; creating each treatment vial expends one use of <em>touch treatment.</em> A treatment vial has the same benefit as his <em>touch treatment,</em> but anyone can administer it as a <strong className="hl">standard action</strong>. A vial can remove any condition the toxitician is able to remove at his mesmerist level, but can't be used for a <em>break enchantment</em> effect. A treatment vial becomes inert after 24 hours.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-toxitician-improved-injections-su" data-hash-target><div className="box">Improved Injections (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Glib lie</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 11th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The toxitician can add two different improvements to an injection. The injection still requires only one save.</div></div></div></div>
</>};
const _umbral_mesmerist = {title: "Umbral Mesmerist", jsx: <><h2 id="arc-mesmerist-umbral_mesmerist-umbral-mesmerist">Umbral Mesmerist</h2>
<p><strong>Sources</strong> <Link to="/source/occult_realms">Occult Realms pg. 16</Link><br/>Trained in secret, umbral mesmerists are clandestine weapons who spend years learning how to shape terrifying creatures from the inky darkness in which they revel.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-umbral_mesmerist-diminished-spellcasting" data-hash-target><div className="box">Diminished Spellcasting</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Spellcasting</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">An umbral mesmerist can cast one fewer spell of each level than normal. If this reduces the number of spells for a level to 0, he can cast spells of that level only if his Charisma score allows <Link to="/rule/bonus_spells">bonus spells</Link> of that level.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-umbral_mesmerist-shadow-summoning-sp" data-hash-target><div className="box">Shadow Summoning (Sp)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Mesmerist tricks gained at 1st, 4th, 8th, 12th, 16th, and 20th levels</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">3 + Charisma modifier times/day</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box"><p>An umbral mesmerist gains the ability to summon quasi-real creatures as per the <Link to="/spell/summon_monster_i">summon monster I</Link> spell. The umbral mesmerist can use this ability as a <strong className="hl">standard action</strong>, and the creatures remain for 1 minute per level (instead of 1 round per level). The creatures summoned are only partly real, but have normal effects unless a creature affected by the illusion succeeds at a Will save to disbelieve (as per <Link to="/spell/shadow_conjuration">shadow conjuration</Link>.) The DC for this save is equal to 10 + 1/2 the umbral mesmerist's mesmerist level + the umbral mesmerist's Charisma modifier. This is an illusion with the shadow descriptor.</p>
<p>A shadow creature has half the hit points of a normal creature of its kind (regardless of whether it is recognized as a shadow creature). It deals the normal amount of damage and has all of the base creature's normal abilities and weaknesses. Against a creature that recognizes it as a shadow creature, however, the shadow creature's damage is halved, and all special abilities that do not deal lethal damage are only 50% likely to work. (Roll for each use and each affected character separately.) Furthermore, the shadow creature's AC bonuses are halved. A creature that succeeds at its save to disbelieve sees the summoned creature as transparent images superimposed on vague, shadowy forms. Objects automatically succeed at their Will saves against this spell. The umbral mesmerist cannot use this ability to summon creatures from more than one <em>summon monster</em> spell in this way at one time.</p>
</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 4th Level</div></div><div className="abEnd"><div className="box">This power of this ability increases to <Link to="/spell/summon_monster_ii">summon monster II</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 8th Level</div></div><div className="abEnd"><div className="box">This power increases to <Link to="/spell/summon_monster_iii">summon monster III</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 12th Level</div></div><div className="abEnd"><div className="box">This ability increases to that of <Link to="/spell/summon_monster_iv">summon monster IV</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 16th Level</div></div><div className="abEnd"><div className="box">This power increases to <Link to="/spell/summon_monster_v">summon monster V</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 20th Level</div></div><div className="abEnd"><div className="box">This power of this ability increases to <Link to="/spell/summon_monster_vi">summon monster VI</Link>.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-umbral_mesmerist-umbral-solipsism-su" data-hash-target><div className="box">Umbral Solipsism (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Towering ego</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">When a creature attempts a Will save to disbelieve a quasi-real creature created by <em>shadow summoning,</em> it takes a penalty on the save equal to the mesmerist's Charisma modifier (minimum 0).</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-umbral_mesmerist-ephemeral-stare-su" data-hash-target><div className="box">Ephemeral Stare (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Mental potency</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The umbral mesmerist is treated as if he were invisible by the target of his <em>hypnotic stare</em> (as per the <Link to="/spell/invisibility">invisibility</Link> spell), provided neither he nor any creatures conjured by <em>shadow summoning</em> take hostile actions against the target. Once the umbral mesmerist or any creature conjured by his <em>shadow summoning</em> ability takes a hostile action against the target, the mesmerist becomes visible to the target and the target cannot be affected again by that umbral mesmerist's <em>ephemeral stare</em> ability for 24 hours (although it can be affected by other effects of his <em>hypnotic stare</em>).</div></div></div></div>
</>};
const _vexing_daredevil = {title: "Vexing Daredevil", jsx: <><h2 id="arc-mesmerist-vexing_daredevil-vexing-daredevil">Vexing Daredevil</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 98</Link><br/>Vexing daredevils train their psychic powers for combat, specializing in momentarily blinding and confusing their foes with sudden feints and tricks.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/skills"><IonIcon icon="/icons/skills.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_daredevil-undefined" data-hash-target><div className="box">Class Skills</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Class skills</div></div></div><div className="abPair"><div className="abStart"><div className="box">New Class Skills</div></div><div className="abEnd"><div className="box"><Link to="/skill/acrobatics">Acrobatics</Link> (DEX)</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_daredevil-martial-weapon-proficiency-ex" data-hash-target><div className="box">Martial Weapon Proficiency (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">1st-level mesmerist trick</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Choice</div></div><div className="abEnd"><div className="box">A vexing daredevil picks one martial weapon and becomes proficient in its use.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_daredevil-bonus-feats" data-hash-target><div className="box">Bonus Feats</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch treatment</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 3rd Level</div></div><div className="abEnd"><div className="box">A vexing daredevil gains <Link to="/feat/improved_feint">Improved Feint</Link> as a bonus feat, even if she doesn't meet its prerequisites.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">She gains <Link to="/feat/greater_feint">Greater Feint</Link> as a bonus feat, even if she doesn't meet its prerequisites.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">She gains <Link to="/feat/greater_mesmerizing_feint">Greater Mesmerizing Feint</Link> as a bonus feat, and doesn't need to meet its prerequisites.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 14th Level</div></div><div className="abEnd"><div className="box">She gains a bonus <Link to="/main/feats_stare">stare feat</Link>; she <strong>must</strong> meet the prerequisites of that feat.</div></div></div></div>
<div className="ability p hasSubs"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_daredevil-dazzling-feint-su" data-hash-target><div className="box">Dazzling Feint (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Bold stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">Each time a vexing daredevil successfully feints against a creature under the effect of her <em>hypnotic stare,</em> she also chooses one of her <em>dazzling feint</em> benefits to activate. Unless otherwise stated, a <em>dazzling feint's</em> benefit applies only on the vexing daredevil's next attack this round.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 3rd Level</div></div><div className="abEnd"><div className="box">She selects her 1st <em>dazzling feint.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 7th Level</div></div><div className="abEnd"><div className="box">She selects her 2nd <em>dazzling feint.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">She selects her 3rd <em>dazzling feint.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 15th Level</div></div><div className="abEnd"><div className="box">She selects her 4th <em>dazzling feint.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 19th Level</div></div><div className="abEnd"><div className="box">She selects her 5th <em>dazzling feint.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">The DC for any saving throw against a <em>dazzling feint's</em> effect is equal to 10 + 1/2 the vexing daredevil's class level + her Charisma modifier. The vexing daredevil can't choose the same <em>dazzling feint</em> more than once.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_daredevil-blinding-strike" data-hash-target><div className="box">Blinding Strike</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The vexing daredevil's weapon emits a bright flash of light into the opponent's eyes. If the vexing daredevil's next attack hits, the target must succeed at a Fortitude saving throw or be <Link to="/misc/blinded">blinded</Link> for 1 round.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_daredevil-combat-maneuver" data-hash-target><div className="box">Combat Maneuver</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The vexing daredevil's attack patterns become more difficult to discern. The vexing daredevil chooses one <Link to="/rule/combat_maneuvers">combat maneuver</Link> when making this <em>dazzling feint.</em> For the rest of the round, she doesn't provoke an attack of opportunity when performing that combat maneuver against the target of her <em>dazzling feint.</em> This <em>dazzling feint</em> benefit applies on combat maneuvers instead of on the vexing daredevil's next attack.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_daredevil-critical-strike" data-hash-target><div className="box">Critical Strike</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">Ever alert, the vexing daredevil hones in on the target's weak points. If her next attack is a critical threat against the target of this <em>dazzling feint,</em> the vexing daredevil gains a circumstance bonus on the roll to confirm that critical hit equal to <Link to="/misc/one_third">one-third</Link> of his mesmerist level.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_daredevil-outmanuever" data-hash-target><div className="box">Outmanuever</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The vexing daredevil's darting movements foil the target's attempts to box her in. If her next attack hits, the vexing daredevil gains a +4 circumstance bonus on Acrobatics checks to move through the target's space or threatened area for 1 round. She can also move up to half her speed after the attack hits as a <strong className="hl">free action</strong>. If she wants to use Acrobatics to move through the target's threatened area or an enemy's space during this movement, she must reduce her speed or the DC of the Acrobatics check increases by 10, as normal.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_daredevil-piercing-strike" data-hash-target><div className="box">Piercing Strike</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">By psychically amplifying the target's pain, the vexing daredevil causes more damage. If she hits with her next attack and deals damage with her <em>painful stare,</em> she increases the damage dice from d6s to d8s.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_daredevil-sloppy-defense" data-hash-target><div className="box">Sloppy Defense</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The vexing daredevil's attacks effortlessly penetrate the target's defenses; she gains a circumstance bonus on her next attack roll equal to one-fifth of his mesmerist level.</div></div></div></div>
<div className="ability p subAbility"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_daredevil-surprise-strike" data-hash-target><div className="box">Surprise Strike</div></div>
<div className="abPair"><div className="abStart"><div className="box">Prerequisites</div></div><div className="abEnd"><div className="box">7th-level mesmerist</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The vexing daredevil creates an opening so she can squeeze in another strike. If her next attack hits, she can make another attack at her highest attack bonus - 5 as a <strong className="hl">free action</strong>.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_daredevil-shimmering-body-sp" data-hash-target><div className="box">Shimmering Body (Sp)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Glib lie</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 11th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">When a vexing daredevil moves in a round, until the beginning of her next turn, any target of her <em>hypnotic stare</em> sees her as a constantly shimmering form of light and treats her as if she were under a <Link to="/spell/blur">blur</Link> spell.</div></div></div></div>
</>};
const _vexing_trickster = {title: "Vexing Trickster", jsx: <><h2 id="arc-mesmerist-vexing_trickster-vexing-trickster">Vexing Trickster</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 19</Link><br/>While many mesmerists are called to embrace the art of deception, using their mind-binding powers to make their foes believe that even the most outrageous realities are actually true, others indulge in the various hijinks their power enables. These mesmerists are known as vexing tricksters.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_trickster-consummate-trickster-ex" data-hash-target><div className="box">Consummate Trickster (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Consummate liar</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A vexing trickster gains a +1 bonus on Bluff, Disguise, Sleight of Hand, and Stealth checks.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 5th Level</div></div><div className="abEnd"><div className="box">This bonus becomes +2.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">This bonus increases to +3.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 13th Level</div></div><div className="abEnd"><div className="box">This bonus becomes +4.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 17th Level</div></div><div className="abEnd"><div className="box">This bonus increases to +5.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_trickster-tricksters-ego-ex" data-hash-target><div className="box">Trickster's Ego (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Towering ego</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A vexing trickster gains <Link to="/feat/combat_expertise">Combat Expertise</Link> as a bonus feat. If his Intelligence score is less than 13, his Intelligence counts as 13 for the purpose of meeting the prerequisites for combat feats.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_trickster-bonus-feat-ex" data-hash-target><div className="box">Bonus Feat (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch treatment (minor), touch treatment (greater)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 3rd Level</div></div><div className="abEnd"><div className="box">A vexing trickster gains a <Link to="/main/feats_trick">trick feat</Link> as a bonus feat. He must meet the feat's prerequisites.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">He gains a second trick feat as a bonus feat.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vexing_trickster-manifold-hijinks-su" data-hash-target><div className="box">Manifold Hijinks (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch treatment (moderate), touch treatment (break enchantment)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 6th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The vexing trickster learns to implant multiple mesmerist tricks that have been modified by trick feats (henceforth called modified tricks) in his targets' minds simultaneously. The vexing trickster can implant up to two modified mesmerist tricks in a single target simultaneously.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 14th Level</div></div><div className="abEnd"><div className="box">He can implant up to three modified mesmerist tricks in a single target simultaneously.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">This ability doesn't allow a mesmerist to apply more than one trick feat to a single mesmerist trick at a time.</div></div></div></div>
</>};
const _vizier = {title: "Vizier", jsx: <><h2 id="arc-mesmerist-vizier-vizier">Vizier</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 38</Link><br/>While many mesmerists focus on beguiling their foes or taking overt control of others with their mental powers, viziers carve out a subtler niche for themselves as advisors. An adventuring vizier is delighted that enemies focus on the raging barbarian or spell-slinging wizard first, not realizing the threat posed by the vizier until it's too late.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vizier-insidious-influence-su" data-hash-target><div className="box">Insidious Influence (Su)</div><div className="flavor">A vizier subtly influences his allies and others who trust him, making it more likely they will follow his suggestions.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Consummate liar, bold stare improvement gained at 3rd level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">Allies with mesmerist tricks implanted by the vizier take penalties on Will saves made to resist the vizier's abilities and spells, and on Diplomacy, Intimidate, Sense Motive checks attempted against the vizier. This penalty equals that imposed by the vizier's <em>hypnotic stare.</em> If the vizier uses his <em>hypnotic stare</em> against such an ally, these penalties stack.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 3rd Level</div></div><div className="abEnd"><div className="box">The vizier automatically gains the <em>susceptibility bold stare</em> improvement, and it also applies to the DCs of any influence check to manipulate the target (even if it isn't Diplomacy or Intimidate).</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vizier-power-behind-the-throne-su" data-hash-target><div className="box">Power Behind the Throne (Su)</div><div className="flavor">The vizier can use his mesmerist powers to make it seem like he is just a hanger-on who isn't contributing to a combat or social situation. This includes making it seem like one of his allies is casting his spells instead.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Towering ego, mental potency</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">When the vizier casts a spell, once the vizier's spell is complete, a glamer subtly alters onlookers' memories and perception of the spell's casting such that all the usual manifestations of the spell indicate that the caster was one of the vizier's allies with an implanted trick. Creatures who observed the spellcasting can attempt a Will save (DC = 10 + 1/2 the vizier's mesmerist level + his Charisma modifier) to disbelieve the glamer.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">Since this effect only comes into play after the spell's casting is complete, any attempts to <Link to="/rule/ready_an_action">ready an action</Link> against the spellcasting, <Link to="/rule/counterspells">counterspell</Link>, or take attacks of opportunity still work as normal. This ability does not prevent or otherwise hinder creatures from correctly targeting such attacks and abilities against the vizier (for instance, a creature readying an action to shoot an arrow to interrupt the spellcasting would still shoot the vizier). Additionally, when the vizier triggers an ally's implanted trick, flashy effects make it appear as if the ally was using an activated ability of her own.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 5th Level</div></div><div className="abEnd"><div className="box">The vizier doesn't provoke attacks of opportunity when using <em>power behind the throne,</em> as if under the effects of a constant <Link to="/spell/illusion_of_calm">illusion of calm</Link>. A creature that disbelieves this second effect becomes immune to that vizier's <em>illusion of calm</em> for 24 hours.</div></div></div></div>
</>};
const _vox = {title: "Vox", jsx: <><h2 id="arc-mesmerist-vox-vox">Vox</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 39</Link><br/>Most mesmerists practice their mental manipulation through their entrancing gaze, but others have learned to practice their skill through the lilt and intonation of their voice. From sibilant whispers to overwhelming imprecations that resonate with the force of pure will, a vox unleashes the power of his mind with every silken syllable and shattering shout.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/spell-book"><IonIcon icon="/icons/spell-book.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vox-spells" data-hash-target><div className="box">Spells</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Towering ego, 10th-level mesmerist trick, touch treatment (break enchantment)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Spellcasting</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">A vox adds the following spells to his class list.</div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">1st</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/ear_piercing_scream">Ear-piercing scream</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">2nd</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/cacophonous_call">Cacophonous call</Link>, <Link to="/spell/disrupt_silence">disrupt silence</Link>, <Link to="/spell/distracting_cacophony">distracting cacophony</Link>, <Link to="/spell/piercing_shriek">piercing shriek</Link>, <Link to="/spell/sonic_scream">sonic scream</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">4th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/shout">Shout</Link>, <Link to="/spell/sonic_thrust">sonic thrust</Link>, <Link to="/spell/wall_of_sound">wall of sound</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">5th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/mass_cacophonous_call">Mass cacophonous call</Link>, <Link to="/spell/echolocation">echolocation</Link>, <Link to="/spell/resonating_word">resonating word</Link></div></div></div>
<div className="abPair"><div className="abStart plain"><div className="box">6th</div></div><div className="abEnd simple"><div className="box"><Link to="/spell/magnifying_chime">Magnifying chime</Link>, <Link to="/spell/greater_shout">greater shout</Link>, <Link to="/spell/sonic_form">sonic form</Link></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">Unlike most psychic spells, a vox's mesmerist spells use both thought and verbal components; like a <Link to="/class/bard">bard</Link>, a vox cannot remove the verbal components of his spells.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vox-compelling-voice-su" data-hash-target><div className="box">Compelling Voice (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Hypnotic stare</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Swift Action</div></div><div className="abEnd"><div className="box">A vox can focus the sound of his voice on one creature within 30 feet, sapping that target's willpower and rendering her more vulnerable to mind-affecting powers, rather than using a stare like other mesmerists.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">A vox can use his <em>compelling voice</em> even while <Link to="/misc/deafened">deafened</Link>, but it has a 20% chance to fail, just like casting a spell with a verbal component. The target does not need to be able to understand what the vox is saying, but does need to be able to hear the sound of the vox's voice (for instance, this ability cannot be used if either the vox or his target is in an area of magical silence). Otherwise, the vox's <em>compelling voice</em> has the effects of the standard mesmerist's <em>hypnotic stare,</em> and it gains further benefits as normal from abilities like the <em>painful stare</em> and <em>bold stare</em> class features.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-palm"><IonIcon icon="/icons/magic-palm.svg" color="secondary" /></Link><Link to="/icons/mailed-fist"><IonIcon icon="/icons/mailed-fist.svg" color="secondary" /></Link><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vox-wounding-words-su" data-hash-target><div className="box">Wounding Words (Su)</div><div className="flavor">A vox can focus the power of his voice to magnify the force of his blows in melee.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch treatment (minor), touch treatment (moderate)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">3 + Charisma modifier times/day</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">A vox can either make a melee touch attack that deals 1d6 points of sonic damage plus 1 point per mesmerist level, or he can make a single attack with a melee weapon, adding the listed sonic damage to the damage dealt by his weapon on a successful attack.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">If the target of the vox's <em>wounding words</em> is also the target of his <em>compelling voice,</em> that creature must succeed at a Will save (DC = 10 + 1/2 the vox's mesmerist level + his Charisma modifier) or take a -2 penalty on attack rolls, saving throws, skill checks, and ability checks for 1 round. This penalty doesn't stack with the effects of the <Link to="/feat/concussive_spell">Concussive Spell</Link> metamagic feat.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/smoking-finger"><IonIcon icon="/icons/smoking-finger.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-mesmerist-vox-subsonic-strike-su" data-hash-target><div className="box">Subsonic Strike (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Touch treatment (major)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 10th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">A vox is able to unleash a deadly flurry of his <em>wounding words</em> at once. He can target a number of creatures or objects equal to his Charisma modifier (minimum 1) within 30 feet, requiring a ranged touch attack against each target. If the target of his <em>compelling voice</em> is within 30 feet, he can choose to instead target only that creature with a single ranged touch or melee touch attack, dealing double normal damage on a successful attack.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">Whatever choice he makes, the vox must expend one use of <em>wounding words.</em></div></div></div></div>
</>};
export default {aromaphile:_aromaphile,autohypnotist:_autohypnotist,chart_caster:_chart_caster,cult_master:_cult_master,dreamstalker:_dreamstalker,enigma:_enigma,eyebiter:_eyebiter,fey_trickster:_fey_trickster,gaslighter:_gaslighter,hate_monger:_hate_monger,material_manipulator:_material_manipulator,mindwyrm_mesmer:_mindwyrm_mesmer,projectionist:_projectionist,spirit_walker:_spirit_walker,thought_eater:_thought_eater,toxitician:_toxitician,umbral_mesmerist:_umbral_mesmerist,vexing_daredevil:_vexing_daredevil,vexing_trickster:_vexing_trickster,vizier:_vizier,vox:_vox}